INSERT INTO `posts` VALUES (1,'Nasi Goreng Sisa Semalam','Menu andalan akhir bulan! Cepat dan enak.','https://images.unsplash.com/photo-1512058564366-18510be2db19?w=500','public',12,1,'2026-07-04 09:18:29','2026-07-04 09:18:29'),(2,'Ayam Kecap Bawang Bombay','Masak ayam kecap kesukaan keluarga. Bumbunya meresap sampai ke dalam daging, mantap!','https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?w=500','public',24,1,'2026-07-04 09:18:29','2026-07-04 09:18:29'),(3,'Sayur Sop Bening Bakso','Cuaca lagi mendung begini paling pas makan yang hangat dan berkuah. Kuahnya seger banget!','https://images.unsplash.com/photo-1547592180-85f173990554?w=500','friends',8,1,'2026-07-04 09:18:29','2026-07-04 09:18:29'),(4,'Telur Dadar Khas Padang','Nyobain resep telur dadar tebal ala rumah makan Padang dari AI SnapChef. Ternyata berhasil dong, tebal dan gurih!','https://images.unsplash.com/photo-1510693206972-df098062cb71?w=500','public',35,1,'2026-07-04 09:18:29','2026-07-04 09:18:29'),(5,'Mie Goreng Spesial','Bikin mie goreng sendiri pakai topping seadanya di kulkas. Kenyang dan praktis buat makan malam.','https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=500','private',0,1,'2026-07-04 09:18:29','2026-07-04 09:18:29');
