INSERT INTO `recipes` VALUES (1,'Nasi Goreng Sisa Semalam','2 piring nasi putih\n1 butir telur\n2 siung bawang putih\nKecap manis secukupnya','1. Tumis bawang putih hingga harum.\n2. Masukkan telur, orak-arik.\n3. Masukkan nasi dan kecap, aduk rata.\n4. Sajikan hangat.',NULL,350,10,45,15,1,'2026-07-04 09:18:29','2026-07-04 09:18:29',0,NULL,'Leftover Fried Rice','2 plates of cooked rice\n1 egg\n2 cloves garlic\nSoy sauce to taste','1. Sauté garlic until fragrant.\n2. Add egg and scramble.\n3. Add rice and soy sauce, stir well.\n4. Serve warm.'),(2,'Mie Goreng','1 bungkus mie \n1 butir telur\n2 siung bawang putih\nKecap manis secukupnya','1. Tumis bawang putih hingga harum.\n2. Masukkan telur, orak-arik.\n3. Masukkan mie yang sudah di rebus dan kecap, aduk rata.\n4. Sajikan hangat.',NULL,250,5,50,10,1,'2026-07-04 09:18:29','2026-07-04 09:18:29',0,NULL,'Fried Noodles','1 pack noodles\n1 egg\n2 cloves garlic\nSoy sauce to taste','1. Sauté garlic until fragrant.\n2. Add egg and scramble.\n3. Add the boiled noodles and soy sauce, stir well.\n4. Serve warm.'),(3,'Ayam Kecap Bawang Bombay','500 gram ayam potong\n1 buah bawang bombay, iris\n3 siung bawang putih, cincang\n4 sdm kecap manis\n1 sdt garam dan lada','1. Tumis bawang putih dan bombay hingga harum.\n2. Masukkan ayam, masak hingga berubah warna.\n3. Tambahkan kecap manis, garam, lada, dan sedikit air.\n4. Masak hingga bumbu meresap dan ayam matang.',NULL,320,25,15,30,1,'2026-07-04 09:18:29','2026-07-04 09:18:29',0,NULL,'Soy Sauce Chicken with Onion','500 grams chicken\n1 onion, sliced\n3 cloves garlic, minced\n4 tbsp sweet soy sauce\n1 tsp salt and pepper','1. Sauté garlic and onion until fragrant.\n2. Add chicken and cook until it changes color.\n3. Add sweet soy sauce, salt, pepper, and a little water.\n4. Cook until the seasoning is absorbed and the chicken is cooked through.'),(4,'Sayur Sop Bening Bakso','2 buah wortel, potong\n1/2 bonggol kubis, potong\n5 buah bakso sapi, belah\n2 siung bawang putih, memarkan\nKaldu bubuk dan seledri secukupnya','1. Didihkan air, masukkan bawang putih memar.\n2. Masukkan wortel dan bakso, masak hingga setengah empuk.\n3. Tambahkan kubis, kaldu bubuk, dan seledri.\n4. Masak sebentar hingga sayuran matang, angkat dan sajikan.',NULL,150,8,20,20,1,'2026-07-04 09:18:29','2026-07-04 09:18:29',0,NULL,'Clear Soup with Meatballs','2 carrots, sliced\n1/2 head cabbage, chopped\n5 beef meatballs, halved\n2 cloves garlic, crushed\nBroth powder and celery to taste','1. Bring water to a boil and add the crushed garlic.\n2. Add carrots and meatballs and cook until halfway tender.\n3. Add cabbage, broth powder, and celery.\n4. Cook briefly until the vegetables are done, then serve.'),(5,'Telur Dadar Khas Padang','3 butir telur ayam/bebek\n2 sdm kelapa parut sangrai\n2 sdm tepung beras\n3 butir bawang merah, iris tipis\n1 sdt bumbu kari bubuk','1. Campur semua bahan dalam mangkuk, kocok hingga rata dan sedikit mengembang.\n2. Panaskan minyak yang cukup banyak di wajan.\n3. Tuang adonan telur, masak dengan api sedang.\n4. Balik perlahan saat bagian bawah sudah kokoh, masak hingga kecoklatan.',NULL,280,18,10,15,1,'2026-07-04 09:18:29','2026-07-04 09:18:29',0,NULL,'Padang-Style Omelette','3 eggs\n2 tbsp toasted grated coconut\n2 tbsp rice flour\n3 shallots, thinly sliced\n1 tsp curry powder','1. Mix all ingredients in a bowl and whisk until smooth and slightly fluffy.\n2. Heat enough oil in a pan.\n3. Pour in the egg mixture and cook over medium heat.\n4. Flip gently once the bottom is set and cook until golden brown.'),(6,'Salad Salmon Segar dengan Saus Minyak Zaitun','1 potong Ikan Salmon (matang, bisa sisa atau dipanggang/goreng sebentar)\n4 lembar Selada\n1 buah Tomat\n2 sdm Kacang Almond (sangrai/panggang sebentar)\n2 sdm Kacang Kenari (sangrai/panggang sebentar)\n1 sdm Biji Wijen (sangrai/panggang sebentar)\n3 sdm Minyak Zaitun (untuk saus)\n1 sdm Air Jeruk Lemon (opsional, jika ada)\nsecukupnya Garam\nsecukupnya Lada Hitam','Jika salmon mentah, panggang atau goreng hingga matang. Dinginkan lalu suwir-suwir.\nCuci bersih selada dan tomat. Potong-potong selada, iris tomat sesuai selera.\nTata selada dan irisan tomat di piring saji. Letakkan suwiran salmon di atasnya.\nTaburkan kacang almond, kacang kenari, dan biji wijen yang sudah disangrai atau dipanggang.\nUntuk saus, campurkan minyak zaitun, air jeruk lemon (jika pakai), garam, dan lada hitam. Aduk rata hingga tercampur sempurna.\nSiramkan saus ke atas salad sesaat sebelum disajikan agar tetap segar.',NULL,380,28,15,15,1,'2026-07-04 09:21:06','2026-07-04 09:21:06',0,'[\"Ikan Salmon\", \"Brokoli\", \"Tomat\", \"Bawang Putih\", \"Beras Campur\", \"Biji Wijen\", \"Kacang Almond\", \"Kacang Kenari\", \"Minyak Zaitun\", \"Selada\", \"Garam\", \"Lada Hitam\"]','Fresh Salmon Salad with Olive Oil Dressing','1 piece Salmon (cooked, can be leftover or briefly baked/fried)\n4 leaves Lettuce\n1 Tomato\n2 tbsp Almonds (toasted/lightly roasted)\n2 tbsp Walnuts (toasted/lightly roasted)\n1 tbsp Sesame Seeds (toasted/lightly roasted)\n3 tbsp Olive Oil (for dressing)\n1 tbsp Lemon Juice (optional, if available)\nSalt to taste\nBlack Pepper to taste','If salmon is raw, bake or fry until cooked. Let it cool, then shred it.\nWash lettuce and tomato thoroughly. Cut lettuce into pieces, slice tomato as desired.\nArrange lettuce and sliced tomato on a serving plate. Place shredded salmon on top.\nSprinkle toasted or roasted almonds, walnuts, and sesame seeds.\nFor the dressing, combine olive oil, lemon juice (if using), salt, and black pepper. Stir well until perfectly mixed.\nPour the dressing over the salad just before serving to keep it fresh.'),(7,'Smoothie Berry Segar','100 gram Stroberi\n50 gram Raspberry\n50 gram Blueberry\n5 buah Ceri\n200 ml Susu cair dingin\n1 buah Pisang\n1 sdm Madu','Cuci bersih semua buah berry. Buang tangkai ceri dan pisahkan dari bijinya jika ada.\nMasukkan semua buah berry, pisang, susu cair, dan madu (jika pakai) ke dalam blender.\nProses hingga halus dan creamy.\nTuang ke dalam gelas dan segera sajikan.',NULL,220,5,45,5,1,'2026-07-04 10:55:27','2026-07-04 10:55:27',0,'[\"Stroberi\", \"Raspberry\", \"Blueberry\", \"Ceri\"]','Fresh Berry Smoothie','100 grams Strawberries\n50 grams Raspberries\n50 grams Blueberries\n5 Cherries\n200 ml cold Milk\n1 Banana\n1 tbsp Honey','Wash all berries thoroughly. Remove cherry stems and pit them if necessary.\nPut all berries, banana, milk, and honey (if using) into a blender.\nBlend until smooth and creamy.\nPour into a glass and serve immediately.'),(8,'Pan-Seared Fish with Roasted Garlic Potatoes and Cucumber Salad','1 potong Fish\n2 buah Potatoes\n2 siung Garlic\n3 sdm Oil\n1 buah Cucumber\n50 gram Lettuce\n1 buah Tomato\nsecukupnya Salt\nsecukupnya Pepper\n2 sdm Mayonnaise','Preheat oven to 200°C (400°F). Wash and cube potatoes. Mince 1 clove of garlic. Toss potatoes with 1 tablespoon of oil, minced garlic, salt, and pepper. Spread on a baking sheet and roast for 20-25 minutes until tender and golden.\nWhile potatoes are roasting, pat the fish fillet dry with paper towels. Season both sides with salt and pepper.\nHeat 2 tablespoons of oil in a non-stick pan over medium-high heat. Carefully place fish in the hot pan. Sear for 3-5 minutes per side, depending on thickness, until cooked through and flaky.\nWash and slice cucumber, tomato, and lettuce. Combine them in a bowl for a simple salad.\nServe the pan-seared fish and roasted potatoes with the fresh cucumber salad. Drizzle with mayonnaise as a dressing for the salad, if desired.',NULL,380,25,35,30,1,'2026-07-04 11:09:50','2026-07-04 11:09:50',0,'[\"Pumpkin\", \"Potatoes\", \"Bok Choy\", \"Cabbage\", \"Okra\", \"Natto\", \"Spinach\", \"Corn\", \"Mayonnaise\", \"Lettuce\", \"Milk\", \"Beef\", \"Garlic\", \"Oil\", \"Green Bell Pepper\", \"Cucumber\", \"Tomato\", \"Fish\", \"Butter\", \"Mushrooms\", \"Rice\", \"Carrot\", \"Sweet Potato\", \"Cheese\", \"Clams\", \"Cinnamon Sticks\", \"Apple\"]','Pan-Seared Fish with Roasted Garlic Potatoes and Cucumber Salad','1 potong Fish\n2 buah Potatoes\n2 siung Garlic\n3 sdm Oil\n1 buah Cucumber\n50 gram Lettuce\n1 buah Tomato\nsecukupnya Salt\nsecukupnya Pepper\n2 sdm Mayonnaise','Preheat oven to 200°C (400°F). Wash and cube potatoes. Mince 1 clove of garlic. Toss potatoes with 1 tablespoon of oil, minced garlic, salt, and pepper. Spread on a baking sheet and roast for 20-25 minutes until tender and golden.\nWhile potatoes are roasting, pat the fish fillet dry with paper towels. Season both sides with salt and pepper.\nHeat 2 tablespoons of oil in a non-stick pan over medium-high heat. Carefully place fish in the hot pan. Sear for 3-5 minutes per side, depending on thickness, until cooked through and flaky.\nWash and slice cucumber, tomato, and lettuce. Combine them in a bowl for a simple salad.\nServe the pan-seared fish and roasted potatoes with the fresh cucumber salad. Drizzle with mayonnaise as a dressing for the salad, if desired.'),(9,'Pasta Ayam Brokoli Saus Keju','200 gram Pasta (Spaghetti atau Fettuccine)\n200 gram Dada Ayam fillet\n150 gram Brokoli\n100 ml Susu cair full cream\n50 gram Keju cheddar\n2 siung Bawang putih\n2 sdm Minyak zaitun\nsecukupnya Garam\nsecukupnya Lada hitam','Rebus pasta hingga al dente, tiriskan dan sisihkan.\nPotong dada ayam menjadi dadu, lumuri dengan sedikit garam dan lada.\nCincang bawang putih. Potong brokoli per kuntum kecil.\nPanaskan minyak zaitun di wajan, tumis bawang putih hingga harum.\nMasukkan ayam, masak hingga berubah warna dan matang. Masukkan brokoli, tumis sebentar hingga sedikit empuk.\nTuang susu cair, masak hingga mendidih. Masukkan keju parut, aduk hingga keju meleleh dan saus mengental.\nMasukkan pasta yang sudah direbus ke dalam saus, aduk rata. Koreksi rasa dengan garam dan lada.\nSajikan selagi hangat.',NULL,450,30,50,25,1,'2026-07-04 11:11:47','2026-07-04 11:11:47',0,'[\"Kentang\", \"Roti Baguette\", \"Roti Gulung\", \"Pasta\", \"Apel\", \"Pisang\", \"Nanas\", \"Jeruk\", \"Anggur\", \"Brokoli\", \"Terong\", \"Tomat\", \"Wortel\", \"Paprika\", \"Mentimun\", \"Selada\", \"Jagung\", \"Seledri\", \"Ikan\", \"Daging Sapi\", \"Ayam\", \"Sosis\", \"Telur\", \"Keju\", \"Susu\", \"Yoghurt\", \"Mentega\", \"Cokelat\"]','Chicken Broccoli Pasta with Cheese Sauce','200 grams Pasta (Spaghetti or Fettuccine)\n200 grams Chicken Breast fillet\n150 grams Broccoli\n100 ml Full Cream Milk\n50 grams Cheddar Cheese\n2 cloves Garlic\n2 tbsp Olive Oil\nto taste Salt\nto taste Black Pepper','Boil pasta until al dente, drain and set aside.\nCut chicken breast into cubes, season with a little salt and pepper.\nMince garlic. Cut broccoli into small florets.\nHeat olive oil in a pan, sauté garlic until fragrant.\nAdd chicken, cook until it changes color and is done. Add broccoli, sauté briefly until slightly tender.\nPour in milk, cook until it boils. Add grated cheese, stir until cheese melts and sauce thickens.\nAdd the cooked pasta to the sauce, mix well. Adjust seasoning with salt and pepper.\nServe warm.');
/*!40000 ALTER TABLE `recipes` ENABLE KEYS */;
