INSERT INTO `scans` VALUES (1,'data:image/jpeg;base64,','[\"Ikan Salmon\",\"Brokoli\",\"Tomat\",\"Bawang Putih\",\"Beras Campur\",\"Biji Wijen\",\"Kacang Almond\",\"Kacang Kenari\",\"Minyak Zaitun\",\"Selada\",\"Garam\",\"Lada Hitam\"]','[{\"id\":1,\"title\":\"Salmon Panggang dengan Brokoli dan Nasi Campur\",\"ingredients\":[\"2 potong Ikan Salmon\",\"1 bonggol Brokoli\",\"2 siung Bawang Putih\",\"1 cangkir Beras Campur\",\"2 sdm Minyak Zaitun\",\"secukupnya Garam\",\"secukupnya Lada Hitam\",\"2 cangkir Air\"],\"steps\":[\"Panaskan oven hingga 200°C. Siapkan loyang.\",\"Cuci bersih brokoli, potong-potong sesuai selera. Cincang halus bawang putih.\",\"Campurkan brokoli dengan 1 sdm minyak zaitun, sejumput garam, dan lada hitam di atas loyang. Panggang selama 10 menit.\",\"Sementara itu, bumbui ikan salmon dengan sisa garam dan lada hitam.\",\"Setelah 10 menit, masukkan ikan salmon ke loyang bersama brokoli. Panggang kembali selama 12-15 menit atau hingga salmon matang sempurna dan brokoli empuk.\",\"Masak beras campur sesuai petunjuk kemasan (umumnya dengan perbandingan 1:2 beras:air).\",\"Sajikan salmon dan brokoli panggang dengan nasi campur hangat.\"],\"calories\":450,\"protein\":35,\"carbs\":40,\"prepTime\":30,\"type\":\"Panggang\"},{\"id\":2,\"title\":\"Salad Salmon Segar dengan Saus Minyak Zaitun\",\"ingredients\":[\"1 potong Ikan Salmon (matang, bisa sisa atau dipanggang/goreng sebentar)\",\"4 lembar Selada\",\"1 buah Tomat\",\"2 sdm Kacang Almond (sangrai/panggang sebentar)\",\"2 sdm Kacang Kenari (sangrai/panggang sebentar)\",\"1 sdm Biji Wijen (sangrai/panggang sebentar)\",\"3 sdm Minyak Zaitun (untuk saus)\",\"1 sdm Air Jeruk Lemon (opsional, jika ada)\",\"secukupnya Garam\",\"secukupnya Lada Hitam\"],\"steps\":[\"Jika salmon mentah, panggang atau goreng hingga matang. Dinginkan lalu suwir-suwir.\",\"Cuci bersih selada dan tomat. Potong-potong selada, iris tomat sesuai selera.\",\"Tata selada dan irisan tomat di piring saji. Letakkan suwiran salmon di atasnya.\",\"Taburkan kacang almond, kacang kenari, dan biji wijen yang sudah disangrai atau dipanggang.\",\"Untuk saus, campurkan minyak zaitun, air jeruk lemon (jika pakai), garam, dan lada hitam. Aduk rata hingga tercampur sempurna.\",\"Siramkan saus ke atas salad sesaat sebelum disajikan agar tetap segar.\"],\"calories\":380,\"protein\":28,\"carbs\":15,\"prepTime\":15,\"type\":\"Salad\"},{\"id\":3,\"title\":\"Tumis Salmon Bawang Putih Tomat dengan Nasi\",\"ingredients\":[\"1 potong Ikan Salmon\",\"3 siung Bawang Putih\",\"2 buah Tomat\",\"1 sdm Minyak Zaitun\",\"1 mangkuk Nasi (dari Beras Campur)\",\"secukupnya Garam\",\"secukupnya Lada Hitam\"],\"steps\":[\"Potong ikan salmon menjadi dadu atau sesuai selera. Bumbui dengan garam dan lada hitam.\",\"Cincang halus bawang putih, iris tomat menjadi beberapa bagian.\",\"Panaskan minyak zaitun di wajan dengan api sedang. Tumis bawang putih hingga harum.\",\"Masukkan potongan salmon, masak hingga berubah warna dan hampir matang di semua sisi.\",\"Tambahkan irisan tomat ke dalam wajan, aduk rata dengan salmon. Masak sebentar hingga tomat sedikit layu namun masih memiliki tekstur.\",\"Koreksi rasa dengan menambahkan garam dan lada hitam sesuai selera.\",\"Sajikan tumis salmon bawang putih tomat ini selagi hangat dengan nasi campur.\"],\"calories\":420,\"protein\":30,\"carbs\":35,\"prepTime\":20,\"type\":\"Tumis\"}]',1,'2026-07-04 09:20:54','2026-07-04 09:20:54','[\"Salmon\",\"Broccoli\",\"Tomato\",\"Garlic\",\"Mixed Rice\",\"Sesame Seeds\",\"Almonds\",\"Walnuts\",\"Olive Oil\",\"Lettuce\",\"Salt\",\"Black Pepper\"]','[{\"id\":1,\"title\":\"Baked Salmon with Broccoli and Mixed Rice\",\"ingredients\":[\"2 pieces Salmon\",\"1 head Broccoli\",\"2 cloves Garlic\",\"1 cup Mixed Rice\",\"2 tbsp Olive Oil\",\"Salt to taste\",\"Black Pepper to taste\",\"2 cups Water\"],\"steps\":[\"Preheat oven to 200°C. Prepare a baking sheet.\",\"Wash broccoli thoroughly, cut into desired pieces. Finely chop garlic.\",\"Combine broccoli with 1 tbsp olive oil, a pinch of salt, and black pepper on the baking sheet. Roast for 10 minutes.\",\"Meanwhile, season the salmon with the remaining salt and black pepper.\",\"After 10 minutes, add the salmon to the baking sheet with the broccoli. Roast again for 12-15 minutes or until salmon is fully cooked and broccoli is tender.\",\"Cook the mixed rice according to package directions (typically with a 1:2 rice:water ratio).\",\"Serve the baked salmon and broccoli with warm mixed rice.\"],\"calories\":450,\"protein\":35,\"carbs\":40,\"prepTime\":30,\"type\":\"Baked\"},{\"id\":2,\"title\":\"Fresh Salmon Salad with Olive Oil Dressing\",\"ingredients\":[\"1 piece Salmon (cooked, can be leftover or briefly baked/fried)\",\"4 leaves Lettuce\",\"1 Tomato\",\"2 tbsp Almonds (toasted/lightly roasted)\",\"2 tbsp Walnuts (toasted/lightly roasted)\",\"1 tbsp Sesame Seeds (toasted/lightly roasted)\",\"3 tbsp Olive Oil (for dressing)\",\"1 tbsp Lemon Juice (optional, if available)\",\"Salt to taste\",\"Black Pepper to taste\"],\"steps\":[\"If salmon is raw, bake or fry until cooked. Let it cool, then shred it.\",\"Wash lettuce and tomato thoroughly. Cut lettuce into pieces, slice tomato as desired.\",\"Arrange lettuce and sliced tomato on a serving plate. Place shredded salmon on top.\",\"Sprinkle toasted or roasted almonds, walnuts, and sesame seeds.\",\"For the dressing, combine olive oil, lemon juice (if using), salt, and black pepper. Stir well until perfectly mixed.\",\"Pour the dressing over the salad just before serving to keep it fresh.\"],\"calories\":380,\"protein\":28,\"carbs\":15,\"prepTime\":15,\"type\":\"Salad\"},{\"id\":3,\"title\":\"Garlic Tomato Stir-fried Salmon with Rice\",\"ingredients\":[\"1 piece Salmon\",\"3 cloves Garlic\",\"2 Tomatoes\",\"1 tbsp Olive Oil\",\"1 bowl Rice (from Mixed Rice)\",\"Salt to taste\",\"Black Pepper to taste\"],\"steps\":[\"Cut salmon into cubes or as desired. Season with salt and black pepper.\",\"Finely chop garlic, slice tomatoes into several pieces.\",\"Heat olive oil in a pan over medium heat. Sauté garlic until fragrant.\",\"Add salmon pieces, cook until color changes and almost cooked on all sides.\",\"Add sliced tomatoes to the pan, stir well with salmon. Cook briefly until tomatoes are slightly wilted but still have texture.\",\"Adjust seasoning by adding salt and black pepper to taste.\",\"Serve this garlic tomato stir-fried salmon hot with mixed rice.\"],\"calories\":420,\"protein\":30,\"carbs\":35,\"prepTime\":20,\"type\":\"Stir-fry\"}]'),(2,'data:image/jpeg;base64,','[\"Stroberi\",\"Raspberry\",\"Blueberry\",\"Ceri\"]','[{\"id\":1,\"title\":\"Smoothie Berry Segar\",\"ingredients\":[\"100 gram Stroberi\",\"50 gram Raspberry\",\"50 gram Blueberry\",\"5 buah Ceri\",\"200 ml Susu cair dingin\",\"1 buah Pisang\",\"1 sdm Madu\"],\"steps\":[\"Cuci bersih semua buah berry. Buang tangkai ceri dan pisahkan dari bijinya jika ada.\",\"Masukkan semua buah berry, pisang, susu cair, dan madu (jika pakai) ke dalam blender.\",\"Proses hingga halus dan creamy.\",\"Tuang ke dalam gelas dan segera sajikan.\"],\"calories\":220,\"protein\":5,\"carbs\":45,\"prepTime\":5,\"type\":\"Minuman\"},{\"id\":2,\"title\":\"Salad Buah Berry Madu Mint\",\"ingredients\":[\"150 gram Stroberi\",\"80 gram Raspberry\",\"80 gram Blueberry\",\"8 buah Ceri\",\"2 sdm Madu\",\"1 sdm Perasan jeruk nipis\",\"5 lembar Daun mint segar\"],\"steps\":[\"Cuci bersih semua buah berry. Potong stroberi dan belah ceri.\",\"Dalam mangkuk besar, campurkan stroberi, raspberry, blueberry, dan ceri.\",\"Dalam mangkuk kecil, campurkan madu, perasan jeruk nipis, dan daun mint cincang. Aduk rata.\",\"Tuang campuran madu ke atas buah berry. Aduk perlahan hingga semua buah terbalut rata.\",\"Sajikan segera atau dinginkan di kulkas selama 15-30 menit untuk rasa yang lebih segar.\"],\"calories\":200,\"protein\":2,\"carbs\":42,\"prepTime\":10,\"type\":\"Salad\"},{\"id\":3,\"title\":\"Kompot Berry Serbaguna\",\"ingredients\":[\"150 gram Stroberi\",\"100 gram Raspberry\",\"100 gram Blueberry\",\"10 buah Ceri\",\"2 sdm Gula pasir\",\"50 ml Air\",\"1 sdm Perasan jeruk lemon\"],\"steps\":[\"Cuci bersih semua buah berry. Potong stroberi dan belah ceri.\",\"Masukkan semua buah berry, gula pasir, air, dan perasan jeruk lemon ke dalam panci kecil.\",\"Masak dengan api sedang, aduk sesekali.\",\"Biarkan mendidih perlahan selama sekitar 5-7 menit atau hingga buah melunak dan saus sedikit mengental. Beberapa buah mungkin akan hancur, itu normal.\",\"Angkat dari api dan biarkan dingin. Kompot akan sedikit lebih kental saat mendingin.\",\"Sajikan sebagai topping untuk yogurt, pancake, es krim, atau roti bakar.\"],\"calories\":280,\"protein\":2,\"carbs\":65,\"prepTime\":15,\"type\":\"Saus\"}]',1,'2026-07-04 10:55:17','2026-07-04 10:55:17','[\"Strawberries\",\"Raspberries\",\"Blueberries\",\"Cherries\"]','[{\"id\":1,\"title\":\"Fresh Berry Smoothie\",\"ingredients\":[\"100 grams Strawberries\",\"50 grams Raspberries\",\"50 grams Blueberries\",\"5 Cherries\",\"200 ml cold Milk\",\"1 Banana\",\"1 tbsp Honey\"],\"steps\":[\"Wash all berries thoroughly. Remove cherry stems and pit them if necessary.\",\"Put all berries, banana, milk, and honey (if using) into a blender.\",\"Blend until smooth and creamy.\",\"Pour into a glass and serve immediately.\"],\"calories\":220,\"protein\":5,\"carbs\":45,\"prepTime\":5,\"type\":\"Beverage\"},{\"id\":2,\"title\":\"Honey Mint Berry Fruit Salad\",\"ingredients\":[\"150 grams Strawberries\",\"80 grams Raspberries\",\"80 grams Blueberries\",\"8 Cherries\",\"2 tbsp Honey\",\"1 tbsp Lime juice\",\"5 fresh Mint leaves\"],\"steps\":[\"Wash all berries thoroughly. Slice strawberries and halve cherries.\",\"In a large bowl, combine strawberries, raspberries, blueberries, and cherries.\",\"In a small bowl, combine honey, lime juice, and chopped mint leaves. Stir well.\",\"Pour the honey mixture over the berries. Stir gently until all fruits are evenly coated.\",\"Serve immediately or chill in the refrigerator for 15-30 minutes for a fresher taste.\"],\"calories\":200,\"protein\":2,\"carbs\":42,\"prepTime\":10,\"type\":\"Salad\"},{\"id\":3,\"title\":\"Versatile Berry Compote\",\"ingredients\":[\"150 grams Strawberries\",\"100 grams Raspberries\",\"100 grams Blueberries\",\"10 Cherries\",\"2 tbsp Granulated sugar\",\"50 ml Water\",\"1 tbsp Lemon juice\"],\"steps\":[\"Wash all berries thoroughly. Slice strawberries and halve cherries.\",\"Put all berries, granulated sugar, water, and lemon juice into a small saucepan.\",\"Cook over medium heat, stirring occasionally.\",\"Let it simmer gently for about 5-7 minutes or until the fruit softens and the sauce thickens slightly. Some fruit may break down, which is normal.\",\"Remove from heat and let it cool. The compote will thicken slightly as it cools.\",\"Serve as a topping for yogurt, pancakes, ice cream, or toast.\"],\"calories\":280,\"protein\":2,\"carbs\":65,\"prepTime\":15,\"type\":\"Sauce\"}]'),(3,'data:image/jpeg;base64,','[\"Labu\",\"Kentang\",\"Pok Coy\",\"Kol\",\"Okra\",\"Natto\",\"Bayam\",\"Jagung\",\"Mayones\",\"Selada\",\"Susu\",\"Daging Sapi\",\"Bawang Putih\",\"Minyak\",\"Paprika Hijau\",\"Mentimun\",\"Tomat\",\"Ikan\",\"Mentega\",\"Jamur\",\"Nasi\",\"Wortel\",\"Ubi Jalar\",\"Keju\",\"Kerang\",\"Batang Kayu Manis\",\"Apel\"]','[{\"id\":1,\"title\":\"Tumis Daging Sapi dan Sayuran dengan Nasi\",\"ingredients\":[\"300 gram Daging Sapi\",\"1 cup Nasi\",\"100 gram Kol\",\"1 buah Wortel\",\"1 buah Paprika Hijau\",\"100 gram Jamur\",\"100 gram Bayam\",\"2 siung Bawang Putih\",\"2 sdm Minyak\",\"secukupnya Garam\",\"secukupnya Lada\"],\"steps\":[\"Masak nasi sesuai petunjuk kemasan. Sisihkan.\",\"Iris tipis daging sapi. Potong kol, wortel, paprika, jamur, dan bayam menjadi potongan seukuran gigitan. Cincang bawang putih.\",\"Panaskan minyak dalam wajan besar di atas api sedang-tinggi. Masukkan bawang putih cincang dan tumis hingga harum, sekitar 30 detik.\",\"Masukkan daging sapi dan tumis hingga kecoklatan dan matang, sekitar 3-5 menit.\",\"Masukkan wortel, paprika, jamur, dan kol ke dalam wajan. Tumis selama 3-5 menit hingga sayuran mulai melunak.\",\"Masukkan bayam dan masak hingga layu, sekitar 1-2 menit. Bumbui dengan garam dan lada secukupnya.\",\"Sajikan tumis daging sapi dan sayuran panas dengan nasi yang sudah dimasak.\"],\"calories\":450,\"protein\":30,\"carbs\":50,\"prepTime\":25,\"type\":\"Tumis\"},{\"id\":2,\"title\":\"Ikan Panggang Wajan dengan Kentang Bawang Putih Panggang dan Salad Mentimun\",\"ingredients\":[\"1 potong Ikan\",\"2 buah Kentang\",\"2 siung Bawang Putih\",\"3 sdm Minyak\",\"1 buah Mentimun\",\"50 gram Selada\",\"1 buah Tomat\",\"secukupnya Garam\",\"secukupnya Lada\",\"2 sdm Mayones\"],\"steps\":[\"Panaskan oven hingga 200°C (400°F). Cuci dan potong kentang dadu. Cincang 1 siung bawang putih. Aduk kentang dengan 1 sendok makan minyak, bawang putih cincang, garam, dan lada. Sebarkan di loyang dan panggang selama 20-25 menit hingga empuk dan keemasan.\",\"Sementara kentang dipanggang, keringkan filet ikan dengan tisu dapur. Bumbui kedua sisi dengan garam dan lada.\",\"Panaskan 2 sendok makan minyak dalam wajan anti lengket di atas api sedang-tinggi. Letakkan ikan dengan hati-hati di wajan panas. Panggang selama 3-5 menit per sisi, tergantung ketebalan, hingga matang dan mudah hancur.\",\"Cuci dan iris mentimun, tomat, dan selada. Campurkan dalam mangkuk untuk salad sederhana.\",\"Sajikan ikan panggang wajan dan kentang panggang dengan salad mentimun segar. Siram dengan mayones sebagai saus salad, jika diinginkan.\"],\"calories\":380,\"protein\":25,\"carbs\":35,\"prepTime\":30,\"type\":\"Panggang Wajan / Panggang Oven\"},{\"id\":3,\"title\":\"Jamur Bawang Putih Krim dengan Bayam dan Nasi\",\"ingredients\":[\"200 gram Jamur\",\"150 gram Bayam\",\"3 siung Bawang Putih\",\"100 ml Susu\",\"1 sdm Mentega\",\"1 sdm Minyak\",\"1 cup Nasi\",\"50 gram Keju\",\"secukupnya Garam\",\"secukupnya Lada\"],\"steps\":[\"Masak nasi sesuai petunjuk kemasan. Sisihkan.\",\"Iris jamur dan cincang bawang putih. Cuci bayam hingga bersih.\",\"Dalam wajan besar, panaskan mentega dan minyak di atas api sedang. Masukkan bawang putih cincang dan tumis hingga harum, sekitar 1 menit.\",\"Masukkan irisan jamur ke dalam wajan dan masak hingga mengeluarkan cairan dan mulai kecoklatan, sekitar 5-7 menit.\",\"Masukkan bayam dan masak hingga layu, sekitar 2-3 menit.\",\"Tuangkan susu dan masak hingga mendidih perlahan. Masukkan keju parut dan aduk hingga meleleh dan krim. Bumbui dengan garam dan lada secukupnya.\",\"Sajikan jamur bawang putih krim dan bayam di atas nasi panas yang sudah dimasak.\"],\"calories\":350,\"protein\":15,\"carbs\":40,\"prepTime\":20,\"type\":\"Krim / Rebusan\"}]',1,'2026-07-04 11:09:37','2026-07-04 11:09:37','[\"Pumpkin\",\"Potatoes\",\"Bok Choy\",\"Cabbage\",\"Okra\",\"Natto\",\"Spinach\",\"Corn\",\"Mayonnaise\",\"Lettuce\",\"Milk\",\"Beef\",\"Garlic\",\"Oil\",\"Green Bell Pepper\",\"Cucumber\",\"Tomato\",\"Fish\",\"Butter\",\"Mushrooms\",\"Rice\",\"Carrot\",\"Sweet Potato\",\"Cheese\",\"Clams\",\"Cinnamon Sticks\",\"Apple\"]','[{\"id\":1,\"title\":\"Beef and Vegetable Stir-fry with Rice\",\"ingredients\":[\"300 gram Beef\",\"1 cup Rice\",\"100 gram Cabbage\",\"1 buah Carrot\",\"1 buah Green Bell Pepper\",\"100 gram Mushrooms\",\"100 gram Spinach\",\"2 siung Garlic\",\"2 sdm Oil\",\"secukupnya Salt\",\"secukupnya Pepper\"],\"steps\":[\"Cook rice according to package instructions. Set aside.\",\"Slice beef thinly. Cut cabbage, carrot, bell pepper, mushrooms, and spinach into bite-sized pieces. Mince garlic.\",\"Heat oil in a large pan or wok over medium-high heat. Add minced garlic and stir-fry until fragrant, about 30 seconds.\",\"Add beef and stir-fry until browned and cooked through, about 3-5 minutes.\",\"Add carrots, bell pepper, mushrooms, and cabbage to the pan. Stir-fry for 3-5 minutes until vegetables start to soften.\",\"Add spinach and cook until wilted, about 1-2 minutes. Season with salt and pepper to taste.\",\"Serve the beef and vegetable stir-fry hot with the cooked rice.\"],\"calories\":450,\"protein\":30,\"carbs\":50,\"prepTime\":25,\"type\":\"Stir-fry\"},{\"id\":2,\"title\":\"Pan-Seared Fish with Roasted Garlic Potatoes and Cucumber Salad\",\"ingredients\":[\"1 potong Fish\",\"2 buah Potatoes\",\"2 siung Garlic\",\"3 sdm Oil\",\"1 buah Cucumber\",\"50 gram Lettuce\",\"1 buah Tomato\",\"secukupnya Salt\",\"secukupnya Pepper\",\"2 sdm Mayonnaise\"],\"steps\":[\"Preheat oven to 200°C (400°F). Wash and cube potatoes. Mince 1 clove of garlic. Toss potatoes with 1 tablespoon of oil, minced garlic, salt, and pepper. Spread on a baking sheet and roast for 20-25 minutes until tender and golden.\",\"While potatoes are roasting, pat the fish fillet dry with paper towels. Season both sides with salt and pepper.\",\"Heat 2 tablespoons of oil in a non-stick pan over medium-high heat. Carefully place fish in the hot pan. Sear for 3-5 minutes per side, depending on thickness, until cooked through and flaky.\",\"Wash and slice cucumber, tomato, and lettuce. Combine them in a bowl for a simple salad.\",\"Serve the pan-seared fish and roasted potatoes with the fresh cucumber salad. Drizzle with mayonnaise as a dressing for the salad, if desired.\"],\"calories\":380,\"protein\":25,\"carbs\":35,\"prepTime\":30,\"type\":\"Pan-Seared / Roasted\"},{\"id\":3,\"title\":\"Creamy Garlic Mushrooms with Spinach and Rice\",\"ingredients\":[\"200 gram Mushrooms\",\"150 gram Spinach\",\"3 siung Garlic\",\"100 ml Milk\",\"1 sdm Butter\",\"1 sdm Oil\",\"1 cup Rice\",\"50 gram Cheese\",\"secukupnya Salt\",\"secukupnya Pepper\"],\"steps\":[\"Cook rice according to package instructions. Set aside.\",\"Slice mushrooms and mince garlic. Wash spinach thoroughly.\",\"In a large pan, heat butter and oil over medium heat. Add minced garlic and sauté until fragrant, about 1 minute.\",\"Add sliced mushrooms to the pan and cook until they release their moisture and start to brown, about 5-7 minutes.\",\"Add spinach and cook until wilted, about 2-3 minutes.\",\"Pour in the milk and bring to a gentle simmer. Add grated cheese and stir until melted and creamy. Season with salt and pepper to taste.\",\"Serve the creamy garlic mushrooms and spinach over the hot cooked rice.\"],\"calories\":350,\"protein\":15,\"carbs\":40,\"prepTime\":20,\"type\":\"Creamy / Stew\"}]'),(4,'data:image/jpeg;base64,','[\"Kentang\",\"Roti Baguette\",\"Roti Gulung\",\"Pasta\",\"Apel\",\"Pisang\",\"Nanas\",\"Jeruk\",\"Anggur\",\"Brokoli\",\"Terong\",\"Tomat\",\"Wortel\",\"Paprika\",\"Mentimun\",\"Selada\",\"Jagung\",\"Seledri\",\"Ikan\",\"Daging Sapi\",\"Ayam\",\"Sosis\",\"Telur\",\"Keju\",\"Susu\",\"Yoghurt\",\"Mentega\",\"Cokelat\"]','[{\"id\":1,\"title\":\"Pasta Ayam Brokoli Saus Keju\",\"ingredients\":[\"200 gram Pasta (Spaghetti atau Fettuccine)\",\"200 gram Dada Ayam fillet\",\"150 gram Brokoli\",\"100 ml Susu cair full cream\",\"50 gram Keju cheddar\",\"2 siung Bawang putih\",\"2 sdm Minyak zaitun\",\"secukupnya Garam\",\"secukupnya Lada hitam\"],\"steps\":[\"Rebus pasta hingga al dente, tiriskan dan sisihkan.\",\"Potong dada ayam menjadi dadu, lumuri dengan sedikit garam dan lada.\",\"Cincang bawang putih. Potong brokoli per kuntum kecil.\",\"Panaskan minyak zaitun di wajan, tumis bawang putih hingga harum.\",\"Masukkan ayam, masak hingga berubah warna dan matang. Masukkan brokoli, tumis sebentar hingga sedikit empuk.\",\"Tuang susu cair, masak hingga mendidih. Masukkan keju parut, aduk hingga keju meleleh dan saus mengental.\",\"Masukkan pasta yang sudah direbus ke dalam saus, aduk rata. Koreksi rasa dengan garam dan lada.\",\"Sajikan selagi hangat.\"],\"calories\":450,\"protein\":30,\"carbs\":50,\"prepTime\":25,\"type\":\"Utama\"},{\"id\":2,\"title\":\"Salad Ikan Bakar dengan Kentang Panggang\",\"ingredients\":[\"200 gram Ikan Salmon fillet (atau ikan Nila/Kakap)\",\"2 buah Kentang ukuran sedang\",\"100 gram Selada romaine\",\"1 buah Tomat\",\"1/2 buah Mentimun\",\"1/2 buah Lemon\",\"3 sdm Minyak zaitun\",\"secukupnya Garam\",\"secukupnya Lada hitam\",\"1/2 sdt Oregano kering (opsional)\"],\"steps\":[\"Cuci bersih ikan, lumuri dengan 1 sdm minyak zaitun, perasan sedikit lemon, garam, dan lada. Diamkan 10 menit.\",\"Kupas kentang, potong dadu atau wedges, lumuri dengan 1 sdm minyak zaitun, garam, lada, dan oregano. Panggang di oven suhu 200°C selama 20-25 menit hingga matang dan renyah.\",\"Panggang atau bakar ikan hingga matang. Bisa juga menggunakan teflon dengan sedikit minyak.\",\"Cuci bersih selada, tomat, dan mentimun. Potong selada, iris tomat dan mentimun.\",\"Untuk dressing: Campurkan sisa minyak zaitun, perasan sisa lemon, sedikit garam, dan lada. Aduk rata.\",\"Tata selada, tomat, mentimun, dan kentang panggang di piring. Letakkan ikan bakar di atasnya.\",\"Siram dengan dressing lemon oil. Sajikan segera.\"],\"calories\":400,\"protein\":35,\"carbs\":30,\"prepTime\":30,\"type\":\"Sehat\"},{\"id\":3,\"title\":\"Omelet Sayuran Keju\",\"ingredients\":[\"3 butir Telur ayam\",\"1/2 buah Paprika (merah atau kuning)\",\"1/2 buah Tomat\",\"30 gram Keju cheddar\",\"1/4 buah Bawang bombay\",\"1 sdm Mentega (atau minyak goreng)\",\"secukupnya Garam\",\"secukupnya Lada hitam\"],\"steps\":[\"Kocok telur bersama garam dan lada hingga rata.\",\"Potong paprika, tomat, dan bawang bombay menjadi dadu kecil.\",\"Parut keju cheddar.\",\"Panaskan mentega di wajan anti lengket dengan api sedang.\",\"Tumis bawang bombay hingga harum. Masukkan paprika dan tomat, tumis sebentar hingga sedikit layu.\",\"Tuang kocokan telur ke atas sayuran, ratakan. Masak hingga bagian bawah omelet mulai matang.\",\"Taburkan keju parut di atas omelet. Lipat omelet menjadi dua atau gulung perlahan.\",\"Masak hingga telur matang sempurna dan keju meleleh. Sajikan hangat.\"],\"calories\":280,\"protein\":18,\"carbs\":10,\"prepTime\":15,\"type\":\"Sarapan\"}]',1,'2026-07-04 11:10:54','2026-07-04 11:10:54','[\"Potatoes\",\"Baguette\",\"Bread Roll\",\"Pasta\",\"Apple\",\"Banana\",\"Pineapple\",\"Orange\",\"Grapes\",\"Broccoli\",\"Eggplant\",\"Tomato\",\"Carrot\",\"Bell Pepper\",\"Cucumber\",\"Lettuce\",\"Corn\",\"Celery\",\"Fish\",\"Beef\",\"Chicken\",\"Sausage\",\"Egg\",\"Cheese\",\"Milk\",\"Yogurt\",\"Butter\",\"Chocolate\"]','[{\"id\":1,\"title\":\"Chicken Broccoli Pasta with Cheese Sauce\",\"ingredients\":[\"200 grams Pasta (Spaghetti or Fettuccine)\",\"200 grams Chicken Breast fillet\",\"150 grams Broccoli\",\"100 ml Full Cream Milk\",\"50 grams Cheddar Cheese\",\"2 cloves Garlic\",\"2 tbsp Olive Oil\",\"to taste Salt\",\"to taste Black Pepper\"],\"steps\":[\"Boil pasta until al dente, drain and set aside.\",\"Cut chicken breast into cubes, season with a little salt and pepper.\",\"Mince garlic. Cut broccoli into small florets.\",\"Heat olive oil in a pan, sauté garlic until fragrant.\",\"Add chicken, cook until it changes color and is done. Add broccoli, sauté briefly until slightly tender.\",\"Pour in milk, cook until it boils. Add grated cheese, stir until cheese melts and sauce thickens.\",\"Add the cooked pasta to the sauce, mix well. Adjust seasoning with salt and pepper.\",\"Serve warm.\"],\"calories\":450,\"protein\":30,\"carbs\":50,\"prepTime\":25,\"type\":\"Main Course\"},{\"id\":2,\"title\":\"Grilled Fish Salad with Roasted Potatoes\",\"ingredients\":[\"200 grams Salmon fillet (or Tilapia/Red Snapper)\",\"2 medium Potatoes\",\"100 grams Romaine Lettuce\",\"1 Tomato\",\"1/2 Cucumber\",\"1/2 Lemon\",\"3 tbsp Olive Oil\",\"to taste Salt\",\"to taste Black Pepper\",\"1/2 tsp Dried Oregano (optional)\"],\"steps\":[\"Wash fish thoroughly, coat with 1 tbsp olive oil, a squeeze of lemon juice, salt, and pepper. Let marinate for 10 minutes.\",\"Peel potatoes, cut into cubes or wedges, coat with 1 tbsp olive oil, salt, pepper, and oregano. Roast in an oven at 200°C for 20-25 minutes until cooked and crispy.\",\"Bake or grill fish until cooked. You can also use a non-stick pan with a little oil.\",\"Wash lettuce, tomato, and cucumber thoroughly. Cut lettuce, slice tomato and cucumber.\",\"For the dressing: Mix remaining olive oil, remaining lemon juice, a little salt, and pepper. Stir well.\",\"Arrange lettuce, tomato, cucumber, and roasted potatoes on a plate. Place grilled fish on top.\",\"Drizzle with lemon oil dressing. Serve immediately.\"],\"calories\":400,\"protein\":35,\"carbs\":30,\"prepTime\":30,\"type\":\"Healthy\"},{\"id\":3,\"title\":\"Cheese Vegetable Omelet\",\"ingredients\":[\"3 Chicken Eggs\",\"1/2 Bell Pepper (red or yellow)\",\"1/2 Tomato\",\"30 grams Cheddar Cheese\",\"1/4 Onion\",\"1 tbsp Butter (or cooking oil)\",\"to taste Salt\",\"to taste Black Pepper\"],\"steps\":[\"Whisk eggs with salt and pepper until well combined.\",\"Cut bell pepper, tomato, and onion into small cubes.\",\"Grate cheddar cheese.\",\"Heat butter in a non-stick pan over medium heat.\",\"Sauté onion until fragrant. Add bell pepper and tomato, sauté briefly until slightly wilted.\",\"Pour whisked eggs over the vegetables, spread evenly. Cook until the bottom of the omelet starts to set.\",\"Sprinkle grated cheese over the omelet. Fold the omelet in half or roll it gently.\",\"Cook until eggs are fully set and cheese is melted. Serve warm.\"],\"calories\":280,\"protein\":18,\"carbs\":10,\"prepTime\":15,\"type\":\"Breakfast\"}]');
